import axios from 'axios';

// URL de base de l'API - affichons la valeur réelle utilisée
const API_URL = process.env.VUE_APP_API_URL || 'http://localhost:5000/api';
console.log('API_URL utilisée:', API_URL);

// Fonction de débogage pour tester la connexion à l'API
export const testApiConnection = async () => {
  try {
    // Test endpoint status
    console.log('Test de connexion à', `${API_URL}/status`);
    const statusResponse = await axios.get(`${API_URL}/status`);
    console.log('Réponse status:', statusResponse.data);
    
    // Test endpoint users
    console.log('Test de connexion à', `${API_URL}/users`);
    const usersResponse = await axios.get(`${API_URL}/users`);
    console.log('Réponse users:', usersResponse.data);
    
    return {
      success: true,
      statusData: statusResponse.data,
      usersData: usersResponse.data
    };
  } catch (error) {
    console.error('Erreur de connexion à l\'API:', error);
    // Afficher les détails de l'erreur
    if (error.response) {
      console.error('Réponse d\'erreur:', error.response.status, error.response.data);
    } else if (error.request) {
      console.error('Pas de réponse reçue:', error.request);
    } else {
      console.error('Erreur de configuration de la requête:', error.message);
    }
    return {
      success: false,
      error: error.message
    };
  }
};

export default {
  testApiConnection
};
